compliant:
public class Foo
{
    [ThreadStatic]
    public static object PerThreadObject; // Compliant - uses default value (null)

    public static object GetPerThreadObject()
    {
        if (PerThreadObject == null)
        {
            PerThreadObject = new object(); // Lazy initialization
        }
        return PerThreadObject;
    }
}

public class Counter
{
    [ThreadStatic]
    private static int? count;

    public static int Count
    {
        get
        {
            count ??= 100; // Compliant - lazy initialization
            return count.Value;
        }
    }
}
